    public DateTime LastInspected { get; set; }
}

namespace InventoryApp.Services;

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate a database or API call
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new() { Id = 1, Name = "Forklift A",        Location = "Warehouse 1", LastInspected = new DateTime(2026, 3, 15) },
            new() { Id = 2, Name = "Conveyor Belt B",    Location = "Warehouse 2", LastInspected = new DateTime(2026, 4, 22) },
            new() { Id = 3, Name = "Pallet Jack C",      Location = "Warehouse 1", LastInspected = new DateTime(2026, 1, 10) },
            new() { Id = 4, Name = "Crane D",            Location = "Yard",        LastInspected = new DateTime(2025, 12, 5) },
            new() { Id = 5, Name = "Drill Press E",      Location = "Workshop",    LastInspected = new DateTime(2026, 5, 1) },
            new() { Id = 6, Name = "Lathe F",            Location = "Workshop",    LastInspected = new DateTime(2026, 2, 18) },
            new() { Id = 7, Name = "Compressor G",       Location = "Utility Room",LastInspected = new DateTime(2026, 4, 30) },
            new() { Id = 8, Name = "Welding Station H",  Location = "Workshop",    LastInspected = new DateTime(2025, 11, 20) },
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using InventoryApp.Services
@inject EquipmentService EquipmentSvc
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _items;
    private PersistingComponentStateSubscription _persistSub;

    protected override async Task OnInitializedAsync()
    {
        // During the interactive render, try to restore data persisted from prerender.
        // If found, skip the service call entirely — data was already fetched once.
        _persistSub = ApplicationState.RegisterOnPersisting(PersistData);

        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>("inventory", out var restored))
        {
            _items = restored;
        }
        else
        {
            _items = await EquipmentSvc.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson("inventory", _items);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistSub.Dispose();
    }
}

